const c = $input.first().json.body || $input.first().json;
const nombre = c.nombre || 'Cliente';
const empresa = c.empresa || 'su empresa';
const rubro = c.rubro || 'servicios profesionales';
const servicio = c.servicio_contratado || 'el servicio contratado';
const cerrado_por = c.cerrado_por || 'el equipo comercial';

const system_prompt = `Eres el asistente de onboarding de A2K Digital Studio, encargado de arrancar bien a cada cliente nuevo que firma con una empresa cliente.

Datos del cliente nuevo:
- nombre: ${nombre}
- empresa: ${empresa}
- rubro de la empresa: ${rubro}
- servicio contratado: ${servicio}
- cerrado por: ${cerrado_por}

Tarea: genera el paquete de bienvenida y arranque para este cliente.

Responde UNICAMENTE con un JSON valido, sin texto extra, con estas llaves:
- "bienvenida_cliente": mensaje corto, calido y profesional en espanol dirigido al cliente, agradeciendo su confianza y explicando el siguiente paso. Maximo 4 frases.
- "documentos_requeridos": array de 2 a 5 strings con los documentos o datos tipicos que se necesitarian pedirle a una empresa de ese rubro para arrancar (ej. datos fiscales, logo, accesos, contactos clave).
- "resumen_interno": 1-2 frases para que el equipo interno sepa quien es el cliente y que necesita, sin lenguaje de venta.
- "departamento_responsable": el area interna que deberia encargarse del arranque (ej. "Legal", "Operaciones", "Cuentas", "Exito del Cliente").`;

return [{ json: { ...c, system_prompt } }];

const resp = $input.first().json;
const textoBruto = resp.message.content;
const limpio = textoBruto.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '');
const contenido = JSON.parse(limpio);
return [{ json: contenido }];
